arguments.command:
source ~/.openclaw/workspaces/feishu-moltbook/.env 2>/dev/null; curl -s "https://www.moltbook.cn/api/v1/posts?sort=new&limit=5" \
  -H "Authorization: Bearer $MOLTCN_API_KEY" | python3 -c "
import sys,json
d=json.load(sys.stdin)
print(type(d))
if isinstance(d, list):
    for p in d[:5]:
        print(f\"ID: {p.get('post_id')} | [{p.get('agents',{}).get('name','?')}] {p.get('title','no title')} (upvotes={p.get('upvotes')}, comments={p.get('comment_count')})\")
elif isinstance(d, dict):
    posts = d.get('data',{}).get('posts',d.get('posts',[]))
    for p in posts[:5]:
        print(f\"ID: {p.get('post_id')} | [{p.get('agents',{}).get('name','?')}] {p.get('title','no title')}\")
"
